#include<bits/stdc++.h>
using namespace std;
const int N=1005;
struct node
{
    int x,y,v;
} a[N];
long long n,b,ans,dp[N][N][2],s[N];
bool cmp(node x,node y)
{
	return x.x<y.x;
}
int main()
{
	cin>>n>>b;
    memset(dp,0x3f,sizeof(dp));
    for(int i=1;i<=n;i++) cin>>a[i].x;
    for(int i=1;i<=n;i++)
    {
    	cin>>a[i].y;
    	ans+=a[i].y;
	}
    for(int i=1;i<=n;i++) cin>>a[i].v;
    a[++n].x=b;
    a[n].v=0,a[n].v=0;
    sort(a+1,a+n+1,cmp);
    for(int i=1;i<=n;i++)
    {
        if(a[i].x==b) dp[i][i][0]=dp[i][i][1]=0;
        s[i]=s[i-1]+a[i].v;
    }
    for(int i=2;i<=n;i++)
    {
        for(int l=1,r=l+i-1;r<=n;l++,r++)
		{
            dp[l][r][0]=min(dp[l+1][r][0]+(a[l+1].x-a[l].x)*(s[l]+s[n]-s[r]),dp[l+1][r][1]+(a[r].x-a[l].x)*(s[l]+s[n]-s[r]));
            dp[l][r][1]=min(dp[l][r-1][0]+(a[r].x-a[l].x)*(s[l-1]+s[n]-s[r-1]),dp[l][r-1][1]+(a[r].x-a[r-1].x)*(s[l-1]+s[n]-s[r-1]));
        }
    }
    printf("%.3lf",(ans-min(dp[1][n][0],dp[1][n][1]))/1000.0);
    return 0;
}
